import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1980年巴菲特致股东的信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1980年/核心总结.md","filePath":"01_letters/1980年/核心总结.md"}'),r={name:"01_letters/1980年/核心总结.md"};function e(n,l,s,p,u,h){return a(),o("div",null,[...l[0]||(l[0]=[i('<h1 id="_1980年巴菲特致股东的信核心总结" tabindex="-1">1980年巴菲特致股东的信核心总结 <a class="header-anchor" href="#_1980年巴菲特致股东的信核心总结" aria-label="Permalink to &quot;1980年巴菲特致股东的信核心总结&quot;">​</a></h1><h2 id="简要导读" tabindex="-1">简要导读 <a class="header-anchor" href="#简要导读" aria-label="Permalink to &quot;简要导读&quot;">​</a></h2><p>1980年这封信最核心的贡献是巴菲特讲透了<strong>非控股股权收益的真实价值</strong>：会计准则只算你拿到的股息，不算你应得的留存收益，但真正的价值来自企业盈利，不管分不分红。这封信也再次强调了高通胀对真实回报的侵蚀，并且对当时保险行业埋的长期债券大雷做出了精准预言，现在读依然触目惊心。GEICO也在这封信正式成为巴菲特最大重仓股。文末可下载英文原版PDF。</p><h2 id="一、会计的假象-你没看见的那一半盈利" tabindex="-1">一、会计的假象：你没看见的那一半盈利 <a class="header-anchor" href="#一、会计的假象-你没看见的那一半盈利" aria-label="Permalink to &quot;一、会计的假象：你没看见的那一半盈利&quot;">​</a></h2><ul><li><p>会计准则对不同持股比例会计处理不一样：</p><ol><li>持股&gt;50%：完全合并所有收入费用</li><li>20%&lt;持股&lt;50%：按比例算进你的收益，分不分红都算</li><li>持股&lt;20%：只算你拿到的股息，留存收益完全不算</li></ol></li><li><p>伯克希尔刚好很多持股都在第三类，很多优秀公司分红少，所以<strong>我们报告的营业收益只露出了冰山一角</strong>——实际上，这些公司留存的未分配盈利，已经超过了伯克希尔总报告营业收益！</p></li><li><p><strong>巴菲特核心观点</strong>：留存收益的价值不取决于有没有计入你的报表，只取决于它们能不能被用好产生更多盈利。&quot;如果一棵树长在我们部分拥有的森林里，哪怕报表没记生长，我们依然拥有这棵树。&quot;</p></li><li><p>我们宁愿没拿到会计记账的盈利，被我们没雇的好管理层用好，也不愿意拿到记账盈利，投到烂项目里——哪怕那个管理层就是我们自己。</p></li><li><p>巴菲特特别喜欢优秀公司回购股票：&quot;如果好企业卖得远低于内在价值，还有什么比用便宜价格回购，放大所有股东权益更确定更赚钱的用途呢？二级市场常常能让你用不到谈判收购一半的价格，买到同样盈利能力。&quot;</p></li></ul><h2 id="二、通胀还是那个小偷-真实回报哪里找" tabindex="-1">二、通胀还是那个小偷：真实回报哪里找 <a class="header-anchor" href="#二、通胀还是那个小偷-真实回报哪里找" aria-label="Permalink to &quot;二、通胀还是那个小偷：真实回报哪里找&quot;">​</a></h2><ul><li><p>巴菲特再提醒：只有<strong>购买力增长才是真实收益</strong>，名义增长没用。12%通胀+你的税率50%，企业赚20%ROE，你拿到的真实回报还是负的——一半交税，剩下10%通胀再吃掉2%，购买力还是缩水了。</p></li><li><p>现在通胀下，平均企业ROE完全被通胀+税收吃掉了，中高收入个人投资者买平均股票，长期不要期待什么真实回报。巴菲特再次坦言：&quot;伯克希尔公司层面也解决不了这个问题。&quot;</p></li></ul><h2 id="三、持仓和重大案例-geico的故事" tabindex="-1">三、持仓和重大案例：GEICO的故事 <a class="header-anchor" href="#三、持仓和重大案例-geico的故事" aria-label="Permalink to &quot;三、持仓和重大案例：GEICO的故事&quot;">​</a></h2><ul><li><p>截至1980年底，伯克希尔已经持有GEICO 720万股，占股33%，成为第一大持仓。总买价4700万美元，对应每年盈利大约2000万美元——也就是买价是盈利的2.35倍！这就是熊市捡垃圾的好处。</p></li><li><p>很多人说GEICO是扭转（turnaround）成功案例，巴菲特不同意：GEICO本来就有不可复制的低成本竞争优势，70年代遇到麻烦只是运营和财务出问题，根本优势没坏。这就像1964年色拉油丑闻后的美国运通，只是切了个局部肿瘤，不是整个生意烂掉，和那种要整个改头换面的真扭转不一样。</p></li><li><p>巴菲特特别赞赏GEICO回购：两年把股份从3420万股减到2160万股，大幅提升了每股价值，&quot;股东不可能得到更好的服务了&quot;。</p></li></ul><h2 id="四、保险行业-大雷已经埋下" tabindex="-1">四、保险行业：大雷已经埋下 <a class="header-anchor" href="#四、保险行业-大雷已经埋下" aria-label="Permalink to &quot;四、保险行业：大雷已经埋下&quot;">​</a></h2><ul><li><p>巴菲特预测：保险行业综合成本率会继续上升，1981-1982承保损失会越来越大。为什么？因为很多保险公司被债券套牢了：</p><ul><li><p>过去买了很多长期债券，现在利率上涨，债券价格大跌，但会计允许按摊余成本持有，不用认跌价。很多公司债券持仓摊余成本是净资产的2-3倍，实际上如果按市价算，很多大保险公司净资产已经没了，甚至负的。</p></li><li><p>这些保险公司不敢认损失，所以动弹不得，没法调整投资，为了维持保费规模拿现金流，只能拼命低价抢业务，哪怕承保亏钱也要卖，整个行业都会被拖下水。巴菲特说这种&quot;保资产承保&quot;，就是&quot;接受烂生意只为保住你现在的资产&quot;，最终整个行业都好不了。</p></li></ul></li><li><p>伯克希尔为什么没事？我们早就不买长期纯债券了，债券持仓也小，所以资本足够，灵活性够，虽然行业差我们也能熬，但行业差我们肯定也好不了。</p></li></ul><h2 id="五、其他业务和事件" tabindex="-1">五、其他业务和事件 <a class="header-anchor" href="#五、其他业务和事件" aria-label="Permalink to &quot;五、其他业务和事件&quot;">​</a></h2><ul><li><p><strong>纺织</strong>：终于砍了Waumbec Mills，巴菲特承认自己错了，没早点面对现实。剩下业务也收缩，聚焦盈利细分，减少资本投入。</p></li><li><p><strong>零售</strong>：联合零售本·罗斯纳76岁了，依然年年出彩，糟糕零售年份依然赚大钱，全部落袋为安，马上要庆祝50周年了。</p></li><li><p><strong>伊利诺伊国民银行</strong>：完成分拆，股东可以选择拿银行股份还是保持伯克希尔，最终平稳过渡，创始人吉恩·阿贝格1980年去世，巴菲特给了他极高评价，说他是完美的银行家，永远诚实可信。</p></li><li><p><strong>融资</strong>：1980年发了6000万12.75%票据，2005年到期。不是现在需要钱，是为未来机会准备好火力，机会来的时候信贷紧缩，我们有钱就能买。&quot;我们偏好能产生现金的企业，不喜欢消耗现金的，保持流动性和充足资本，睡得香。&quot;</p></li></ul><h2 id="六、核心启示" tabindex="-1">六、核心启示 <a class="header-anchor" href="#六、核心启示" aria-label="Permalink to &quot;六、核心启示&quot;">​</a></h2><ol><li><strong>财报会骗人</strong>：不要只看报表上的每股收益，非控股的留存收益也是你的，只要企业能把留存收益用好，长期自然会体现到市值上。</li><li><strong>通胀是小偷</strong>：高通胀时期，哪怕企业ROE不低，税后真实回报也可能是负的，这个问题到今天依然存在。</li><li><strong>不撞南墙不回头的行业问题最可怕</strong>：保险公司当年不敢承认债券损失，只能低价抢业务，把整个行业拖下水，这种问题在各个行业周期里反复出现。</li><li><strong>留足现金准没错</strong>：没事的时候借钱攒火力，熊市机会来的时候你有钱，别人没钱，这就是最大的优势。</li></ol><hr><blockquote><p>📎 <strong>文末小惊喜</strong>：可点击下载<a href="Chairman&#39;s%20Letter%20-%201980.pdf">巴菲特1980年股东信原件PDF</a>，原汁原味阅读英文原文。</p></blockquote>',17)])])}const q=t(r,[["render",e]]);export{c as __pageData,q as default};
